file.template:
#!/bin/bash # Voice Agent Deployment Script
set -e # Exit on error set -u # Exit on undefined variable
# Color codes RED='\033[0;31m' GREEN='\033[0;32m' YELLOW='\033[1;33m' NC='\033[0m'
# Configuration SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)" CONFIG_DIR="${SCRIPT_DIR}/configs" CREDENTIALS_FILE="${SCRIPT_DIR}/credentials.yaml" LOG_FILE="${SCRIPT_DIR}/deployment.log"
# Functions log() { echo "[$(date +'%Y-%m-%d %H:%M:%S')] $1" | tee -a "${LOG_FILE}" }
error() { echo -e "${RED}[ERROR] $1${NC}" | tee -a "${LOG_FILE}" exit 1 }
success() { echo -e "${GREEN}[SUCCESS] $1${NC}" | tee -a "${LOG_FILE}" }
warning() { echo -e "${YELLOW}[WARNING] $1${NC}" | tee -a "${LOG_FILE}" }
check_prerequisites() { log "Checking prerequisites..."
if [ ! -f "${CREDENTIALS_FILE}" ]; then error "Credentials file not found: ${CREDENTIALS_FILE}" fi
if ! command -v python3 &> /dev/null; then error "Python 3 is required but not installed" fi
if ! command -v wxo &> /dev/null; then error "watsonx Orchestrate ADK not installed" fi
success "Prerequisites check passed" }
load_credentials() { log "Loading credentials..." # Load credentials from file export $(cat "${CREDENTIALS_FILE}" | grep -v '^#' | xargs) success "Credentials loaded" }
deploy_agent() { log "Deploying agent..." wxo agent import "${CONFIG_DIR}/agent.yaml" success "Agent deployed" }
deploy_voice_config() { log "Deploying voice configuration..." wxo voice-config import "${CONFIG_DIR}/voice_config.yaml" success "Voice configuration deployed" }
deploy_channels() { log "Deploying channels..."
if [ -f "${CONFIG_DIR}/channels/phone_config.yaml" ]; then wxo phone-config import "${CONFIG_DIR}/channels/phone_config.yaml" success "Phone config deployed" fi
if [ -f "${CONFIG_DIR}/channels/whatsapp_config.yaml" ]; then wxo channel import "${CONFIG_DIR}/channels/whatsapp_config.yaml" success "WhatsApp channel deployed" fi
success "All channels deployed" }
deploy_tools() { log "Deploying tools..."
for tool_file in "${CONFIG_DIR}"/tools/*.py; do if [ -f "$tool_file" ]; then wxo tool import python "$tool_file" success "Deployed tool: $(basename $tool_file)" fi done
success "All tools deployed" }
validate_deployment() { log "Validating deployment..."
# Check agent exists wxo agent list | grep -q "agent-name" || error "Agent not found"
# Check voice config exists wxo voice-config list | grep -q "voice-config-name" || error "Voice config not found"
success "Deployment validation passed" }
rollback() { log "Rolling back deployment..." warning "Rollback not yet implemented" # Add rollback logic here }
deploy_all() { check_prerequisites load_credentials deploy_agent deploy_voice_config deploy_channels deploy_tools validate_deployment success "Deployment completed successfully!" }
# Main script case "${1:-}" in deploy-all) deploy_all ;; deploy-agent) check_prerequisites load_credentials deploy_agent ;; deploy-voice-config) check_prerequisites load_credentials deploy_voice_config ;; deploy-channels) check_prerequisites load_credentials deploy_channels ;; deploy-tools) check_prerequisites load_credentials deploy_tools ;; validate) validate_deployment ;; rollback) rollback ;; *) echo "Usage: $0 {deploy-all|deploy-agent|deploy-voice-config|deploy-channels|deploy-tools|validate|rollback}" exit 1 ;; esac
